  { domain: "stradivarius.com", type: "Buyer" },
  { domain: "tjx.com", type: "Buyer" },
  { domain: "ovs.it", type: "Buyer" },
  { domain: "conceptclothing.co.in", type: "Internal" },
  { domain: "styleisland.com", type: "Internal"}
];

// Always promotional - grows over time as client reports
const ALWAYS_PROMOTIONAL = [
  "nsdl.com"
];

// Always miscellaneous (banking, compliance, etc) - grows over time
const ALWAYS_MISCELLANEOUS = [
  "nesl.co.in",
  "wrapcompliance.org"
];

// BBG/Roxy domains
const BBG_ROXY_DOMAINS = [
  "boardriders.com.tw",
  "boardriders.co.jp",
  "bhaus.co.il",
  "actionbrandslatam.com",
  "boardriders.mx",
  "quiksilver.com.ar",
  "olgar.com.tr",
  "ccc.eu",
  "brkcompany.kr",
  "boardriders.co.za"
];

const VIKRAM_EMAIL = "vikram@conceptclothing.co.in";
const VIKRAM_NAMES = ["vikram", "vikram mehta", "sir"];

// Get all emails from Normalize
const items = $input.all().map(i => i.json);

const results = items.map(norm => {
  const senderDomain = (norm.sender_domain || "").toLowerCase().trim();

  // Check hardcoded lists first (highest priority)
  if (ALWAYS_PROMOTIONAL.includes(senderDomain)) {
    return {
      ...norm,
      sender_type: "Promotional",
      addressed_to_me: false
    };
  }

  if (ALWAYS_MISCELLANEOUS.includes(senderDomain)) {
    return {
      ...norm,
      sender_type: "Miscellaneous",
      addressed_to_me: false
    };
  }

  if (BBG_ROXY_DOMAINS.includes(senderDomain)) {
    return {
      ...norm,
      sender_type: "BBG_Roxy",
      addressed_to_me: false
    };
  }

  // Match domain against business list
  const match = DOMAIN_LIST.find(r => r.domain === senderDomain);

  // Determine sender_type
  let sender_type = "Unknown";
  if (match) {
    sender_type = match.type === "Internal" ? "Internal" : "Buyer";
  }

  // Check for internal employee emailing BBG/Roxy
  if (sender_type === "Internal") {
    const toList = Array.isArray(norm.to) ? norm.to : [];
    const ccList = Array.isArray(norm.cc) ? norm.cc : [];
    const allRecipients = [...toList, ...ccList];

    const hasBBGRecipient = allRecipients.some(x => {
      const addr = x?.emailAddress?.address || "";
      const recipientDomain = addr.split("@")[1]?.toLowerCase().trim() || "";
      return BBG_ROXY_DOMAINS.includes(recipientDomain);
    });

    if (hasBBGRecipient) {
      return {
        ...norm,
        sender_type: "BBG_Roxy",
        addressed_to_me: false
      };
    }
  }

  // Addressed-to-me check: ONLY for Buyer or Internal
  // Must have Vikram in To AND his name in first line of body
  let addressed_to_me = false;

  if (sender_type === "Buyer" || sender_type === "Internal") {
    const toList = Array.isArray(norm.to) ? norm.to : [];
    const inTo = toList.some(x => {
      const addr = x?.emailAddress?.address || "";
      return addr.toLowerCase().trim() === VIKRAM_EMAIL.toLowerCase();
    });

    const firstLine = (norm.body || "")
      .split(/\r?\n/)
      .map(line => line.trim())
      .find(line => line.length > 0) || "";

    const nameInFirstLine = VIKRAM_NAMES.some(name =>
      firstLine.toLowerCase().includes(name)
    );

    addressed_to_me = inTo && nameInFirstLine;
  }

  return {
    ...norm,
    sender_type,
    addressed_to_me
  };
});

return results;

// Get message_id from AI_input for this item
const messageId = $node["AI_input"].json.message_id || null;

// Extract raw text from AI output
const raw = $input.item.json.content.parts[0].text;

let ai;
try {
  ai = JSON.parse(raw);
} catch (e) {
  return {
  final_label: "Needs review",
  confidence: 0,
  messageId: messageId,
  folderId: "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACwZ1zJwAAAA=="
};
}

let final_label = ai.bucket_label;
const confidence = Number(ai.confidence ?? 0);

if (confidence <= 0.6) {
  final_label = "Needs review";
}

const allowed = [
  "Addressed to me",
  "Urgent",
  "Normal priority",
  "Needs review",
  "Miscellaneous",
  "Promotions",
  "BBG/Roxy"
];

if (!allowed.includes(final_label)) {
  final_label = "Needs review";
}

const folderMap = {
  "Addressed to me": "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACwZ1zJQAAAA==",
  "Urgent": "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACwZ1zJAAAAA==",
  "Normal priority": "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACwZ1zJgAAAA==",
  "Needs review": "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACwZ1zJwAAAA==",
  "Miscellaneous": "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACwxusDAAAAA==",
  "Promotions": "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACwxusCwAAAA==",
  "BBG/Roxy": "AQMkADU3OGI0MWQwLWRjZWEtNDA2OS04MmE5LTY3MDM5MGVmYzVmZAAuAAADkrEgFtpjc0qhSL6htCeiCQEAIkOvDngUhkaW3dzeF0QyMwACw77UNQAAAA=="
};

const folderId = folderMap[final_label];

return {
  ...ai,
  final_label,
